#!/usr/bin/env python3
"""TASK-7: Restructure hubbard_u_sweep_slurm/main.rs: extract build_one_task + build_sweep_tasks functions, add --local flag + castep_command to SweepConfig, use iterator chain, fix anyhow conversion"""
import base64, json, subprocess, sys

TASK_ID = "TASK-7"
STEPS = json.loads('[{"before_b64": "ICAgIC8vLyBEcnktcnVuIG1vZGU6IHByaW50IHRvcG9sb2dpY2FsIG9yZGVyIGFuZCBleGl0IHdpdGhvdXQgc3VibWl0dGluZwogICAgI1thcmcobG9uZyldCiAgICBwdWIgZHJ5X3J1bjogYm9vbCwKfQ==", "after_b64": "", "target": "examples/hubbard_u_sweep_slurm/src/config.rs", "index": 0}, {"before_b64": "", "after_b64": "", "target": "examples/hubbard_u_sweep_slurm/src/main.rs", "index": 1}]')

for step in STEPS:
    before = base64.b64decode(step["before_b64"]).decode()
    after = base64.b64decode(step["after_b64"]).decode()
    target = step["target"]
    idx = step["index"]

    content = open(target).read()
    if before not in content:
        print(f"FAILED {TASK_ID} change {idx}: pattern not found in {target}", file=sys.stderr)
        print(f"Expected (first 200 chars): {repr(before[:200])}", file=sys.stderr)
        sys.exit(1)

    result = subprocess.run(
        ["sd", "-F", "-A", "-n", "1", before, after, target],
        capture_output=True, text=True,
    )
    if result.returncode != 0:
        print(f"FAILED {TASK_ID} change {idx}: sd error: {result.stderr}", file=sys.stderr)
        sys.exit(result.returncode)

    new_content = open(target).read()
    if after and after not in new_content:
        print(f"FAILED {TASK_ID} change {idx}: replacement not found after apply", file=sys.stderr)
        sys.exit(1)

    print(f"OK {TASK_ID} change {idx}: applied to {target}")

print(f"OK {TASK_ID}: all changes applied")
